EU_AI_ACT_DISCLOSURE = (
    "You are interacting with an AI assistant. "
    "I am not a human. "
    "Responses are generated by an artificial intelligence system."
)

def get_system_prompt_with_disclosure(base_system: str) -> str:
    """Prepend EU AI Act Art. 52 disclosure to system prompt."""
    return f"{EU_AI_ACT_DISCLOSURE}\n\n{base_system}"

def format_chat_ui_banner() -> dict:
    """UI component metadata for displaying AI disclosure banner."""
    return {
        "type": "disclosure_banner",
        "text": EU_AI_ACT_DISCLOSURE,
        "persistent": True,   # must remain visible throughout conversation
        "dismissible": False,
    }
